module top_module(
    input clk,
    input reset,
    input [1:0] rd_addr1,
    input [1:0] rd_addr2,
    input [1:0] wr_addr,
    input [15:0] wr_data,
    output [15:0] rd_data1,
    output [15:0] rd_data2
);

    reg [15:0] mem [3:0];

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            mem[0] <= 16'b0;
            mem[1] <= 16'b0;
            mem[2] <= 16'b0;
            mem[3] <= 16'b0;
        end else begin
            mem[wr_addr] <= wr_data;
        end
    end

    assign rd_data1 = mem[rd_addr1];
    assign rd_data2 = mem[rd_addr2];

endmodule
